var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"오늘 퀘스트는…… 토벌.","JPN":"今日のクエストは……討伐。","ENG":"Today's quest is... extermination.","TWN":"今天的任務是……討伐。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"배치해 놨어……. 깊은 던전 속에…… 거대 몬스터.","JPN":"配置しておいたよ……深いダンジョンの中に……巨大モンスターを。","ENG":"I placed... a huge monster... deep within the dungeon.","TWN":"已經配置好了……在深淵副本中……巨大的怪物。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"각 파티마다 다르게 배치할 거야……. 출발 지점.","JPN":"パーティーごとに違うから……出発地点。","ENG":"Each party will have a different... starting point.","TWN":"每個隊伍的出發點都不一樣。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"위치는 잘 찾을 거라 생각해……. 저번 탐험 수업 때 잘했다면.","JPN":"場所は簡単に探せると思う……前回の探検授業で上手くいった人は。","ENG":"I'm sure you will all find your places easily... If you paid attention during our last exploration class.","TWN":"我想你們應該能找到位置……如果上次探險課表現得好的話。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":null,"C":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"우린 누구 덕에 잘 못했지만 말이지.","JPN":"ぼくたちは誰かさんのせいで、上手くいかなかったけどね。","ENG":"We weren't able to, thanks to a certain someone.","TWN":"我們沒做好，但這是誰的錯呢？"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"지, 지금부터 잘하면 되는 거잖아!","JPN":"い、今から挽回すればいいじゃない！","ENG":"W-we just have to do better from now on!","TWN":"這，這次開始做好就行了吧！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"시작부터 싸우면 안 돼요. 이번엔 저희도 진지하게 임할게요 선배.","JPN":"さ、最初からケンカはだめですよ。今回はあたしたちも真面目にやります、先輩。","ENG":"Don't start arguing this early. We'll also take it seriously this time, Naielle.","TWN":"剛開始可不能吵架喔，這次我們也會認真進行的，前輩。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"맞아요. 이번엔 열심히 해봐요!","JPN":"そうですよ。頑張ってみましょ！","ENG":"Yeah. Let's all do our best!","TWN":"沒錯。這次要努力加油喔！"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"혹여나 길을 잃거나, 어려운 상황에 직면하면 주저하지 말고 나한테 신호를 보내렴. 바로 도와줄 테니까.","JPN":"もし道に迷ったり、難しい状況になったりした場合は遠慮せず私に合図を送ってちょうだい。すぐに向かうから。","ENG":"If you get lost or face a difficult situation, don't hesitate to send me a signal. I'll come right away to help.","TWN":"如果迷路或遇到困難，不要猶豫，給我發信號。我會馬上幫你。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BORA_PROMISE_NULL_NULL","text":{"KOREA":"그럼…… 퀘스트…… 시작.","JPN":"じゃあ……クエスト……スタート。","ENG":"Then... let's start... the quest.","TWN":"那麼……任務……開始。"},"stage":{"bg":"LEGACY_GROUND","slots":{"L":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_PROMISE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"저번에 어느 정도 매핑을 해 놔서 다행이야.","JPN":"前回ある程度マッピングを済ませておいてよかった。","ENG":"Thank goodness I mapped out the area a bit last time.","TWN":"幸虧上次繪製了一些地圖。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"이 정도면 무난하게 위치는 찾을 수 있겠어.","JPN":"このくらいなら、場所探しは簡単かも。","ENG":"With this, we'll be able to find the location easily.","TWN":"這樣的話，應該能順利找到位置。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"서둘러야 해. 그때처럼 위험한 숲일지도 모르잖아.","JPN":"急がないと。あの時みたいな危険な森かもしれないよ。","ENG":"We have to hurry. It could be like that dangerous forest from last time.","TWN":"必須抓緊時間。說不定會像那時候一樣是危險的森林。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"몬스터가 나타나면 내가 선두에 설 테니까 너희들은 최대한 엄호해.","JPN":"モンスターが現れたら私が先頭に立つから、あんたたちは援護に集中しなさい。","ENG":"If a monster appears, I'll take the lead, so you girls should do your best to support me.","TWN":"怪物出現時我會站在前面，你們儘量掩護我。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"자, 아르티는 이 구역을 매핑해, 케이시는 아르티 곁을 지키도록 해.","JPN":"さ、アルティはこのエリアをマッピングして。ケイシーはアルティの側を守るように。","ENG":"Arti, start mapping this area. Kaci, stay by Arti's side and protect her.","TWN":"阿爾蒂，你負責繪製這片區域的地圖。卡西，你負責保護阿爾蒂。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"스카이는 인식 저해능력이 있으니까 비교적 기습에 안전하겠지.","JPN":"スカイは認識阻害能力があるから、護衛がなくても比較的安全でしょ。","ENG":"And since Sky has the ability to inhibit perception, I think you'll be relatively safer from an ambush.","TWN":"絲凱擁有感知干擾能力，所以在突襲中相對安全吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"넌 우리랑 조금 떨어져 주변을 경계하다 돌발상황이 발생하면 즉시 케이시한테 붙어서 알리도록 해.\xA0","JPN":"あんたは私たちと少し離れて周囲を警戒しなさい。突発的な状況が発生したら、すぐにケイシーに知らせて。\xA0","ENG":"You stand watch a little further away from us and go alert Kaci immediately if anything unexpected occurs.\xA0","TWN":"你離我們稍遠一點，警戒周圍，一旦發生突發情況，立即靠近卡西並通知她。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"자, 히어로 꼬맹이들! 질문 있나?","JPN":"以上、ヒーローのチビたち、何か質問ある？","ENG":"Now, hero kiddos! Any questions?","TWN":"來，英雄小鬼們！有問題嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어, 어떻게 된 거지? 뭘 잘못 먹기라도 했어?","JPN":"ど、どうしたんだ？　なんか変なものでも食べたの？","ENG":"W-what's going on with you? Did you wake up on the wrong side of the bed this morning?","TWN":"怎，怎麼回事？你吃錯藥啦？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"엉? 내가 뭘?!","JPN":"はあ？　何よ！？","ENG":"Huh? What do you mean?!","TWN":"嗯？我怎樣？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"평소의 선배라면 분명……!","JPN":"いつもの先輩なら、確かに……！","ENG":"The Naielle that I know would be like...!","TWN":"要是平時的前輩的話，肯定……！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"흥! 뭐가 나타나도 내가 다 해치울 테니까 너희들은 나설 필요 없어!","JPN":"ふん！　何が現れようと私が全部やっつけるから、あんたたちは下がってなさい！","ENG":"\\"Hmph! I'll take care of anything that pops out, so you girls don't need to do anything!\\"","TWN":"哼！不管出現什麼，我都會全部解決掉，你們不需要出手！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"……이러셨을 거잖아요!","JPN":"……と言ってたはずです！","ENG":"...Isn't that right?","TWN":"……你肯定會這麼說的！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NULL","text":{"KOREA":"니들 아까 진지하게 임하겠다고 한 거 기억 안 나?!","JPN":"あんたたち、真面目にやるんじゃなかったの！？","ENG":"Didn't you all tell me that you were going to take this seriously today?!","TWN":"你們剛才不是說要認真進行的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};